selector_to_html = {"a[href=\"keyboard.html#character-encoding-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es de Codifica\u00e7\u00e3o<a class=\"headerlink\" href=\"#character-encoding-settings\" title=\"Link to this heading\">#</a></h2><h3>Tipos originais<a class=\"headerlink\" href=\"#original-types\" title=\"Link to this heading\">#</a></h3>", "a[href=\"codedelay.html#disable-same-code-scanning\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Desativar mesma varredura de c\u00f3digo<a class=\"headerlink\" href=\"#disable-same-code-scanning\" title=\"Link to this heading\">#</a></h2>", "a[href=\"keyboard.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es de teclado<a class=\"headerlink\" href=\"#keyboard-settings\" title=\"Link to this heading\">#</a></h1><h2>Configura\u00e7\u00f5es Caso<a class=\"headerlink\" href=\"#case-settings\" title=\"Link to this heading\">#</a></h2><p>Voc\u00ea pode configurar a sa\u00edda para ser todas mai\u00fasculas ou todas min\u00fasculas</p>", "a[href=\"character.html#end-character-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Finalizar Configura\u00e7\u00f5es do Personagem<a class=\"headerlink\" href=\"#end-character-settings\" title=\"Link to this heading\">#</a></h2><p>O caractere final \u00e9 adicionado ap\u00f3s os dados decodificados no formato de dados decodificados + caractere final.</p>", "a[href=\"character.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Exterminador<a class=\"headerlink\" href=\"#terminator\" title=\"Link to this heading\">#</a></h1><h2>Finalizar Configura\u00e7\u00f5es do Personagem<a class=\"headerlink\" href=\"#end-character-settings\" title=\"Link to this heading\">#</a></h2><p>O caractere final \u00e9 adicionado ap\u00f3s os dados decodificados no formato de dados decodificados + caractere final.</p>", "a[href=\"system.html#volume-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es de Volume<a class=\"headerlink\" href=\"#volume-settings\" title=\"Link to this heading\">#</a></h2><p>Voc\u00ea pode ajustar o volume da campainha escaneando o seguinte c\u00f3digo de configura\u00e7\u00e3o, de acordo com o ambiente da aplica\u00e7\u00e3o e h\u00e1bitos pessoais.</p>", "a[href=\"qrcodeurl.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es de URL do c\u00f3digo QR<a class=\"headerlink\" href=\"#qr-code-url-settings\" title=\"Link to this heading\">#</a></h1><p>Bloqueie a verifica\u00e7\u00e3o de c\u00f3digos QR de URL come\u00e7ando com <code class=\"docutils literal notranslate\"><span class=\"pre\">http://</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">https://</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">www.</span></code></p>", "a[href=\"qrcodeurl.html#enable-url-code\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Habilitar c\u00f3digo URL<a class=\"headerlink\" href=\"#enable-url-code\" title=\"Link to this heading\">#</a></h2>", "a[href=\"codedelay.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">3000ms<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">#</a></h2>", "a[href=\"system.html#restore-default-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Restaurar configura\u00e7\u00f5es padr\u00e3o<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Link to this heading\">#</a></h2><p>Quando um erro desconhecido ocorre no scanner, voc\u00ea pode redefinir o scanner restaurando as configura\u00e7\u00f5es padr\u00e3o.</p>", "a[href=\"keyboard.html#case-settings\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es Caso<a class=\"headerlink\" href=\"#case-settings\" title=\"Link to this heading\">#</a></h2><p>Voc\u00ea pode configurar a sa\u00edda para ser todas mai\u00fasculas ou todas min\u00fasculas</p>", "a[href=\"codedelay.html#ms\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">0ms<a class=\"headerlink\" href=\"#ms\" title=\"Link to this heading\">#</a></h2>", "a[href=\"qrcodeurl.html#disable-url-code\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Desativar C\u00f3digo URL<a class=\"headerlink\" href=\"#disable-url-code\" title=\"Link to this heading\">#</a></h2>", "a[href=\"codedelay.html#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">500ms<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">#</a></h2>", "a[href=\"codedelay.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es de Atraso de C\u00f3digo Mesmo<a class=\"headerlink\" href=\"#same-code-delay-settings\" title=\"Link to this heading\">#</a></h1><p>Para evitar que o mesmo c\u00f3digo de barras seja lido v\u00e1rias vezes consecutivas durante a varredura, voc\u00ea pode definir um limite de tempo antes de permitir que o mesmo c\u00f3digo de barras seja lido.</p>", "a[href=\"system.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Configura\u00e7\u00f5es do Sistema<a class=\"headerlink\" href=\"#system-settings\" title=\"Link to this heading\">#</a></h1><h2>Restaurar configura\u00e7\u00f5es padr\u00e3o<a class=\"headerlink\" href=\"#restore-default-settings\" title=\"Link to this heading\">#</a></h2><p>Quando um erro desconhecido ocorre no scanner, voc\u00ea pode redefinir o scanner restaurando as configura\u00e7\u00f5es padr\u00e3o.</p>", "a[href=\"system.html#get-firmware-version\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Obter vers\u00e3o do Firmware<a class=\"headerlink\" href=\"#get-firmware-version\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#nt-2010-payment-platform-quick-setup-guide\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Guia de configura\u00e7\u00e3o r\u00e1pida da plataforma de pagamento <strong>NT-2010</strong><a class=\"headerlink\" href=\"#nt-2010-payment-platform-quick-setup-guide\" title=\"Link to this heading\">#</a></h1>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
